// MARK: - Utilities

enum Hex {
    static func encode(_ data: Data) -> String {
        data.map { String(format: "%02x", $0) }.joined()
    }

    static func decode(_ hex: String) throws -> Data {
        let s = hex.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        guard s.count % 2 == 0 else { throw WalletError.invalidHex }
        var data = Data()
        data.reserveCapacity(s.count / 2)
        var idx = s.startIndex
        while idx < s.endIndex {
            let next = s.index(idx, offsetBy: 2)
            let byteStr = s[idx..<next]
            guard let b = UInt8(byteStr, radix: 16) else { throw WalletError.invalidHex }
            data.append(b)
            idx = next
        }
        return data
    }
}

extension Data {
    func sha256() -> Data {
        Data(SHA256.hash(data: self))
    }
}

enum Base58Check {
    private static let alphabet = Array("123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz")

    static func encode(_ payload: Data) -> String {
        var data = payload
        let checksum = data.sha256().sha256().prefix(4)
        data.append(checksum)

        var x = [UInt8](data)
        var zeros = 0
        while zeros < x.count && x[zeros] == 0 { zeros += 1 }

        var digits = [Int](repeating: 0, count: x.count * 2)
        var digitLen = 1

        for byte in x {
            var carry = Int(byte)
            var i = 0
            while i < digitLen {
                carry += digits[i] << 8
                digits[i] = carry % 58
                carry /= 58
                i += 1
            }
            while carry > 0 {
                digits[digitLen] = carry % 58
                digitLen += 1
                carry /= 58
            }
        }

        var result = String(repeating: "1", count: zeros)
        for i in stride(from: digitLen - 1, through: 0, by: -1) {
            result.append(alphabet[digits[i]])
        }
        return result
    }
}

