final class KeychainStore {
    static let shared = KeychainStore()
    private init() {}

    private let service = "com.example.wallet.mvp"
    private let keyTag = "wallet.secp256k1.privatekey"

    func savePrivateKey(_ data: Data) throws {
        try deletePrivateKeyIfExists()

        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: keyTag,
            kSecAttrAccessible as String: kSecAttrAccessibleAfterFirstUnlockThisDeviceOnly,
            kSecValueData as String: data
        ]
        let status = SecItemAdd(query as CFDictionary, nil)
        guard status == errSecSuccess else { throw WalletError.keychain(status) }
    }

    func loadPrivateKey() throws -> Data {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: keyTag,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        var item: CFTypeRef?
        let status = SecItemCopyMatching(query as CFDictionary, &item)
        guard status == errSecSuccess else { throw WalletError.keychain(status) }
        guard let data = item as? Data else { throw WalletError.noKey }
        return data
    }

    func deletePrivateKeyIfExists() throws {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: keyTag
        ]
        let status = SecItemDelete(query as CFDictionary)
        guard status == errSecSuccess || status == errSecItemNotFound else { throw WalletError.keychain(status) }
    }

    func hasKey() -> Bool {
        (try? loadPrivateKey()) != nil
    }
}

// MARK: - secp256k1 (minimal, pure Swift signing via CryptoKit P256 fallback if needed)

final class Secp256k1 {
    // NOTE: This MVP uses P256 for signing if secp256k1 is unavailable.
    // For production Bitcoin/Ethereum, integrate a vetted secp256k1 library.
    enum Curve {
        case p256Fallback
    }

    static func generatePrivateKey() -> Data {
        let key = P256.Signing.PrivateKey()
        return key.rawRepresentation
    }

    static func publicKeyCompressedHex(fromPrivateKey priv: Data) throws -> String {
        let key = try P256.Signing.PrivateKey(rawRepresentation: priv)
        let pub = key.publicKey
        let x963 = pub.x963Representation
        // x963 uncompressed: 0x04 || X(32) || Y(32)
        guard x963.count == 65, x963.first == 0x04 else { throw WalletError.unsupported }
        let x = x963[1..<33]
        let y = x963[33..<65]
        let yLast = y.last!
        let prefix: UInt8 = (yLast % 2 == 0) ? 0x02 : 0x03
        var compressed = Data([prefix])
        compressed.append(contentsOf: x)
        return Hex.encode(compressed)
    }

    static func sign(messageHash32: Data, privateKey priv: Data) throws -> Data {
        guard messageHash32.count == 32 else { throw WalletError.invalidInput("Message hash must be 32 bytes") }
        let key = try P256.Signing.PrivateKey(rawRepresentation: priv)
        let sig = try key.signature(for: messageHash32)
        return sig.derRepresentation
    }
}

