// MARK: - Wallet Service

final class WalletService {
    static let shared = WalletService()
    private init() {}

    private let keychain = KeychainStore.shared
    private let walletDefaultsKey = "wallet.metadata"

    func currentWallet() -> Wallet? {
        guard let data = UserDefaults.standard.data(forKey: walletDefaultsKey) else { return nil }
        return try? JSONDecoder().decode(Wallet.self, from: data)
    }

    func createWalletIfNeeded() throws -> Wallet {
        if let w = currentWallet(), keychain.hasKey() { return w }
        let priv = Secp256k1.generatePrivateKey()
        try keychain.savePrivateKey(priv)
        let pubHex = try Secp256k1.publicKeyCompressedHex(fromPrivateKey: priv)
        let addr = try Address.makeAddress(fromCompressedPubKeyHex: pubHex)
        let wallet = Wallet(id: UUID(), createdAt: Date(), curve: "P-256 (MVP fallback)", publicKeyCompressedHex: pubHex, address: addr)
        let data = try JSONEncoder().encode(wallet)
        UserDefaults.standard.set(data, forKey: walletDefaultsKey)
        return wallet
    }

    func deleteWallet() throws {
        try keychain.deletePrivateKeyIfExists()
        UserDefaults.standard.removeObject(forKey: walletDefaultsKey)
    }

    func signTransaction(_ tx: UnsignedTransaction) throws -> SignedTransaction {
        guard let wallet = currentWallet() else { throw WalletError.invalidInput("No wallet") }
        let priv = try keychain.loadPrivateKey()

        let canonical = try canonicalTransactionBytes(tx)
        let hash = canonical.sha256()
        let sigDER = try Secp256k1.sign(messageHash32: hash, privateKey: priv)
        let sigHex = Hex.encode(sigDER)
        let txHash = hash.sha256()
        return SignedTransaction(unsigned: tx,
                                 signatureHex: sigHex,
                                 publicKeyCompressedHex: wallet.publicKeyCompressedHex,
                                 txHashHex: Hex.encode(txHash))
    }

    private func canonicalTransactionBytes(_ tx: UnsignedTransaction) throws -> Data {
        var dict: [String: Any] = [
            "chain": tx.chain,
            "from": tx.fromAddress,
            "to": tx.toAddress,
            "amount": tx.amount,
            "nonce": tx.nonce,
            "fee": tx.fee
        ]
        if let memo = tx.memo { dict["memo"] = memo }

        let keys = dict.keys.sorted()
        var parts: [String] = []
        for k in keys {
            let v = dict[k]!
            parts.append("\(k)=\(v)")
        }
        let s = parts.joined(separator: "&")
        guard let data = s.data(using: .utf8) else { throw WalletError.encoding }
        return data
    }
}

// MARK: - Blockchain Communication (MVP JSON-RPC style)

final class BlockchainClient {
    static let shared = BlockchainClient()
    private init() {}

    struct RPCRequest: Codable {
        let jsonrpc: String
        let id: Int
        let method: String
        let params: [String: CodableValue]
    }

    struct RPCResponse: Codable {
        let jsonrpc: String?
        let id: Int?
        let result: CodableValue?
        let error: RPCError?
    }

    struct RPCError: Codable {
        let code: Int
        let message: String
        let data: CodableValue?
    }

    enum CodableValue: Codable, Equatable {
        case string(String)
        case int(Int)
        case uint64(UInt64)
        case double(Double)
        case bool(Bool)
        case object([String: CodableValue])
        case array([CodableValue])
        case null

        init(from decoder: Decoder) throws {
            let c = try decoder.singleValueContainer()
            if c.decodeNil() { self = .null; return }
            if let v = try? c.decode(Bool.self) { self = .bool(v); return }
            if let v = try? c.decode(Int.self) { self = .int(v); return }
            if let v = try? c.decode(UInt64.self) { self = .uint64(v); return }
            if let v = try? c.decode(Double.self) { self = .double(v); return }
            if let v = try? c.decode(String.self) { self = .string(v); return }
            if let v = try? c.decode([String: CodableValue].self) { self = .object(v); return }
            if let v = try? c.decode([CodableValue].self) { self = .array(v); return }
            throw WalletError.decoding
        }

        func encode(to encoder: Encoder) throws {
            var c = encoder.singleValueContainer()
            switch self {
            case .string(let v): try c.encode(v)
            case .int(let v): try c.encode(v)
            case .uint64(let v): try c.encode(v)
            case .double(let v): try c.encode(v)
            case .bool(let v): try c.encode(v)
            case .object(let v): try c.encode(v)
            case .array(let v): try c.encode(v)
            case .null: try c.encodeNil()
            }
        }
    }

    func call(url: URL, method: String, params: [CodableValue]) async throws -> CodableValue {
        let req = RPCRequest(jsonrpc: "2.0", id: Int.random(in: 1...Int.max), method: method, params: params)
        let body = try JSONEncoder().encode(req)

        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = body
        request.timeoutInterval = 20

        let (data, resp) = try await URLSession.shared.data(for: request)
        guard let http = resp as? HTTPURLResponse else { throw WalletError.network("No HTTP response") }
        guard (200..<300).contains(http.statusCode) else {
            throw WalletError.network("HTTP \(http.statusCode): \(String(data: data, encoding: .utf8) ?? "")")
        }

        let decoded = try JSONDecoder().decode(RPCResponse.self, from: data)
        if let err = decoded.error {
            throw WalletError.network("RPC error \(err.code): \(err.message)")
        }
        guard let result = decoded.result else { throw WalletError.network("No result") }
        return result
    }

    func broadcastSignedTransaction(url: URL, signed: SignedTransaction) async throws -> CodableValue {
        let payload: [String: CodableValue] = [
            "chain": .string(signed.unsigned.chain),
            "from": .string(signed.unsigned.fromAddress),
            "to": .string(signed.unsigned.toAddress),
            "amount": .string(signed.unsigned.amount),
            "nonce": .uint64(signed.unsigned.nonce),
            "fee": .string(signed.unsigned.fee),
            "memo": signed.unsigned.memo.map { .string($0) } ?? .null,
            "signature": .string(signed.signatureHex),
            "pubkey": .string(signed.publicKeyCompressedHex),
            "txHash": .string(signed.txHashHex)
        ]
        return try await call(url: url, method: "broadcastTransaction", params: [.object(payload)])
    }

    func getBalance(url: URL, address: String) async throws -> CodableValue {
        try await call(url: url, method: "getBalance", params: [.string(address)])
    }
}

// MARK: - UI

final class WalletViewController: UIViewController {
    private let walletService = WalletService.shared
    private let client = BlockchainClient.shared

    private let scroll = UIScrollView()
    private let stack = UIStackView()

    private let walletLabel = UILabel()
    private let addressLabel = UILabel()
    private let pubKeyLabel = UILabel()

    private let rpcURLField = UITextField()
    private let balanceButton = UIButton(type: .system)
    private let balanceLabel = UILabel()

    private let toField = UITextField()
    private let amountField = UITextField()
    private let feeField = UITextField()
    private let nonceField = UITextField()
    private let memoField = UITextField()

    private let signButton = UIButton(type: .system)
    private let signedTextView = UITextView()
    private let broadcastButton = UIButton(type: .system)

    private let resetButton = UIButton(type: .system)

    private var wallet: Wallet?

    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Wallet MVP"
        view.backgroundColor = .systemBackground
        setupUI()
        loadWallet()
    }

    private func setupUI() {
        scroll.translatesAutoresizingMaskIntoConstraints = false
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 12

        view.addSubview(scroll)
        scroll.addSubview(stack)

        NSLayoutConstraint.activate([
            scroll.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            scroll.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            scroll.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scroll.bottomAnchor.constraint(equalTo: view.bottomAnchor),

            stack.leadingAnchor.constraint(equalTo: scroll.contentLayoutGuide.leadingAnchor, constant: 16),
            stack.trailingAnchor.constraint(equalTo: scroll.contentLayoutGuide.trailingAnchor, constant: -16),
            stack.topAnchor.constraint(equalTo: scroll.contentLayoutGuide.topAnchor, constant: 16),
            stack.bottomAnchor.constraint(equalTo: scroll.contentLayoutGuide.bottomAnchor, constant: -16),
            stack.widthAnchor.constraint(equalTo: scroll.frameLayoutGuide.widthAnchor, constant: -32)
        ])

        walletLabel.font = .preferredFont(forTextStyle: .headline)
        walletLabel.numberOfLines = 0
        addressLabel.font = .preferredFont(forTextStyle: .subheadline)
        addressLabel.numberOfLines = 0
        pubKeyLabel.font = .preferredFont(forTextStyle: .footnote)
        pubKeyLabel.numberOfLines = 0

        rpcURLField.borderStyle = .roundedRect
        rpcURLField.placeholder = "RPC URL (e.g. https://example.com/rpc)"
        rpcURLField.autocapitalizationType = .none
        rpcURLField.keyboardType = .URL
        rpcURLField.text = "https://example.com/rpc"

        balanceButton.setTitle("Get Balance", for: .normal)
        balanceButton.addTarget(self, action: #selector(getBalanceTapped), for: .touchUpInside)
        balanceLabel.numberOfLines = 0
        balanceLabel.font = .preferredFont(forTextStyle: .footnote)

        toField.borderStyle = .roundedRect
        toField.placeholder = "To Address"
        toField.autocapitalizationType = .none

        amountField.borderStyle = .roundedRect
        amountField.placeholder = "Amount"
        amountField.keyboardType = .decimalPad

        feeField.borderStyle = .roundedRect
        feeField.placeholder = "Fee"
        feeField.keyboardType = .decimalPad
        feeField.text = "0.0001"

        nonceField.borderStyle = .roundedRect
        nonceField.placeholder = "Nonce"
        nonceField.keyboardType = .numberPad
        nonceField.text = "1"

        memoField.borderStyle = .roundedRect
        memoField.placeholder = "Memo (optional)"

        signButton.setTitle("Sign Transaction", for: .normal)
        signButton.addTarget(self, action: #selector(signTapped), for: .touchUpInside)

        signedTextView.isEditable = false
        signedTextView.font = UIFont.monospacedSystemFont(ofSize: 12, weight: .regular)
        signedTextView.layer.borderWidth = 1
        signedTextView.layer.borderColor = UIColor.separator.cgColor
        signedTextView.layer.cornerRadius = 8
        signedTextView.heightAnchor.constraint(equalToConstant: 220).isActive = true

        broadcastButton.setTitle("Broadcast Signed Tx", for: .normal)
        broadcastButton.addTarget(self, action: #selector(broadcastTapped), for: .touchUpInside)

