        stack.addArrangedSubview(addressLabel)
        stack.addArrangedSubview(pubKeyLabel)

        stack.addArrangedSubview(makeSectionTitle("Blockchain"))
        stack.addArrangedSubview(rpcURLField)
        stack.addArrangedSubview(balanceButton)
        stack.addArrangedSubview(balanceLabel)

        stack.addArrangedSubview(makeSectionTitle("Create Transaction"))
