    private func makeSectionTitle(_ text: String) -> UILabel {
        let l = UILabel()
        l.text = text
        l.font = .preferredFont(forTextStyle: .headline)
        return l
    }

    private func loadWallet() {
        do {
            let w = try walletService.createWalletIfNeeded()
            wallet = w
            walletLabel.text = "Wallet: \(w.id.uuidString)\nCreated: \(DateFormatter.localizedString(from: w.createdAt, dateStyle: .medium, timeStyle: .short))\nCurve: \(w.curve)"
            addressLabel.text = "Address:\n\(w.address)"
            pubKeyLabel.text = "Public Key (compressed hex):\n\(w.publicKeyCompressedHex)"
        } catch {
            walletLabel.text = "Wallet error: \(error.localizedDescription)"
        }
    }

    @objc private func getBalanceTapped() {
        guard let w = wallet else { return }
        guard let url = URL(string: rpcURLField.text ?? "") else {
            balanceLabel.text = "Invalid RPC URL"
            return
        }
        balanceLabel.text = "Loading..."
        Task {
            do {
                let result = try await client.getBalance(url: url, address: w.address)
                await MainActor.run {
                    balanceLabel.text = "Balance result:\n\(pretty(result))"
                }
            } catch {
                await MainActor.run {
                    balanceLabel.text = "Balance error: \(error.localizedDescription)"
                }
            }
        }
    }

    @objc private func signTapped() {
        guard let w = wallet else { return }
        let to = (toField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let amount = (amountField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let fee = (feeField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let memo = (memoField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)
        let nonceStr = (nonceField.text ?? "").trimmingCharacters(in: .whitespacesAndNewlines)

        guard !to.isEmpty else { signedTextView.text = "Missing to address"; return }
        guard !amount.isEmpty else { signedTextView.text = "Missing amount"; return }
        guard !fee.isEmpty else { signedTextView.text = "Missing fee"; return }
        guard let nonce = UInt64(nonceStr) else { signedTextView.text = "Invalid nonce"; return }

        let tx = UnsignedTransaction(chain: "MVP-CHAIN",
                                     fromAddress: w.address,
                                     toAddress: to,
                                     amount: amount,
                                     nonce: nonce,
                                     fee: fee,
                                     memo: memo.isEmpty ? nil : memo)
        do {
            let signed = try walletService.signTransaction(tx)
            let data = try JSONEncoder().encode(signed)
            signedTextView.text = String(data: data, encoding: .utf8) ?? ""
        } catch {
            signedTextView.text = "Sign error: \(error.localizedDescription)"
        }
    }

    @objc private func broadcastTapped() {
        guard let url = URL(string: rpcURLField.text ?? "") else {
            signedTextView.text = "Invalid RPC URL"
            return
        }
        guard let data = signedTextView.text.data(using: .utf8),
              let signed = try? JSONDecoder().decode(SignedTransaction.self, from: data) else {
            signedTextView.text = "No valid signed transaction JSON to broadcast"
            return
        }

        Task {
            do {
                let result = try await client.broadcastSignedTransaction(url: url, signed: signed)
                await MainActor.run {
                    signedTextView.text = (signedTextView.text ?? "") + "\n\nBroadcast result:\n\(pretty(result))"
                }
            } catch {
                await MainActor.run {
                    signedTextView.text = (signedTextView.text ?? "") + "\n\nBroadcast error:\n\(error.localizedDescription)"
                }
            }
        }
    }

    @objc private func resetTapped() {
        let alert = UIAlertController(title: "Delete Wallet?",
                                      message: "This will delete the private key from Keychain on this device. Funds may be lost if you have no backup.",
                                      preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        alert.addAction(UIAlertAction(title: "Delete", style: .destructive, handler: { [weak self] _ in
            guard let self else { return }
            do {
                try self.walletService.deleteWallet()
                self.wallet = nil
                self.walletLabel.text = "Wallet deleted."
                self.addressLabel.text = ""
                self.pubKeyLabel.text = ""
                self.signedTextView.text = ""
                self.balanceLabel.text = ""
                self.loadWallet()
            } catch {
                self.walletLabel.text = "Reset error: \(error.localizedDescription)"
            }
        }))
        present(alert, animated: true)
    }

    private func pretty(_ value: BlockchainClient.CodableValue) -> String {
        func toAny(_ v: BlockchainClient.CodableValue) -> Any {
            switch v {
            case .string(let s): return s
            case .int(let i): return i
            case .uint64(let u): return u
            case .double(let d): return d
            case .bool(let b): return b
            case .object(let o): return Dictionary(uniqueKeysWithValues: o.map { ($0.key, toAny($0.value)) })
            case .array(let a): return a.map(toAny)
            case .null: return NSNull()
            }
        }
        let any = toAny(value)
        if JSONSerialization.isValidJSONObject(any),
           let data = try? JSONSerialization.data(withJSONObject: any, options: [.prettyPrinted, .sortedKeys]),
           let s = String(data: data, encoding: .utf8) {
            return s
        }
        return "\(any)"
    }
}